import{_ as t,o as r,c as l,ae as e}from"./chunks/framework.BMMOQqto.js";const g=JSON.parse('{"title":"Q5: 项目中JVM调优问题？如何排查和解决？","description":"","frontmatter":{},"headers":[],"relativePath":"01-java/q5-jvm-tuning.md","filePath":"01-java/q5-jvm-tuning.md"}'),o={name:"01-java/q5-jvm-tuning.md"};function i(n,a,s,h,d,c){return r(),l("div",null,[...a[0]||(a[0]=[e('<h1 id="q5-项目中jvm调优问题-如何排查和解决" tabindex="-1">Q5: 项目中JVM调优问题？如何排查和解决？ <a class="header-anchor" href="#q5-项目中jvm调优问题-如何排查和解决" aria-label="Permalink to &quot;Q5: 项目中JVM调优问题？如何排查和解决？&quot;">​</a></h1><h2 id="常见jvm问题" tabindex="-1">常见JVM问题 <a class="header-anchor" href="#常见jvm问题" aria-label="Permalink to &quot;常见JVM问题&quot;">​</a></h2><ul><li><strong>OOM（内存溢出）</strong>：堆内存不足、内存泄漏、MetaSpace不足</li><li><strong>频繁GC</strong>：年轻代太小、大对象直接进老年代、内存碎片</li><li><strong>GC停顿长</strong>：老年代碎片化、FULL GC频繁</li><li><strong>内存泄漏</strong>：长连接未关闭、静态集合引用、ThreadLocal未清理</li></ul><h2 id="排查工具" tabindex="-1">排查工具 <a class="header-anchor" href="#排查工具" aria-label="Permalink to &quot;排查工具&quot;">​</a></h2><ul><li><strong>jstat -gcutil PID 1000</strong>：查看GC统计，每秒更新</li><li><strong>jmap -heap PID</strong>：查看堆配置和使用</li><li><strong>jmap -dump:format=b,file=heap.hprof PID</strong>：导出堆转储</li><li><strong>MAT</strong>：分析堆转储文件，定位内存泄漏</li><li><strong>Arthas</strong>：在线诊断，dashboard、heapdump、watch</li></ul><h2 id="实际案例-支付记录查询优化" tabindex="-1">实际案例：支付记录查询优化 <a class="header-anchor" href="#实际案例-支付记录查询优化" aria-label="Permalink to &quot;实际案例：支付记录查询优化&quot;">​</a></h2><h3 id="问题背景" tabindex="-1">问题背景 <a class="header-anchor" href="#问题背景" aria-label="Permalink to &quot;问题背景&quot;">​</a></h3><p>嘉立创EFS应收账款结算中台，600万+支付记录查询响应时间15秒+</p><h3 id="排查过程" tabindex="-1">排查过程 <a class="header-anchor" href="#排查过程" aria-label="Permalink to &quot;排查过程&quot;">​</a></h3><ol><li>通过EXPLAIN分析SQL执行计划，发现全表扫描</li><li>定位到分区表在跨片排序时执行计划不优</li><li>确认索引选择性低，部分查询走错索引</li><li>jstat发现年轻代频繁Minor GC</li></ol><h3 id="解决方案" tabindex="-1">解决方案 <a class="header-anchor" href="#解决方案" aria-label="Permalink to &quot;解决方案&quot;">​</a></h3><ol><li><strong>全局路由索引</strong>：针对常用查询条件创建复合索引</li><li><strong>局部时间索引</strong>：按时间范围快速定位数据</li><li><strong>索引下推</strong>：在索引层过滤数据，减少回表次数</li><li><strong>Parallel Query</strong>：开启MySQL并行查询</li></ol><h3 id="优化结果" tabindex="-1">优化结果 <a class="header-anchor" href="#优化结果" aria-label="Permalink to &quot;优化结果&quot;">​</a></h3><p>查询响应时间：15秒 → 3秒，性能提升5倍</p>',14)])])}const m=t(o,[["render",i]]);export{g as __pageData,m as default};
